-- Add 4 missing intel cards: Bali, Chiang Mai, Lisbon, Spiti Valley.
--
-- These four destinations were anticipated by scripts/refresh-intel-images.ts
-- (their slugs are mapped to Wikipedia article titles for hero images) but
-- never had an intel card seeded into the intel_cards table — so the live
-- site rendered them as locked / empty.
--
-- The card content here is byte-identical to what was simultaneously appended
-- to lib/mock-data/intel-cards.json, so the JSON seed and the live DB stay
-- in sync.
--
-- UPSERT (ON CONFLICT DO UPDATE) so this migration also overwrites any
-- partial admin-draft rows that already exist for these slugs.

INSERT INTO intel_cards (
  slug, destination, country, audience, contributor_slug, last_updated, verified_by_count, hero_image_url,
  tldr, neighborhoods, scams, transport, hidden_gems, pre_book_checklist, dos_and_donts,
  estimated_daily_budget, emergency_numbers, is_premium, premium_preview, affiliate_links
)
VALUES
(
  'bali-indonesia',
  'Bali',
  'Indonesia',
  'both',
  'ananya-mumbai',
  '2026-04-28'::date,
  7,
  '/images/intel/bali-indonesia.jpg',
  '["Money-changer short-counts cost women $50–$300 per swap on Kuta and Legian high streets — only use Central Kuta Money Exchange, BMC, or Dirgahayu (4.5+ stars on Maps). Count notes yourself before walking away.","Scooter rental: NEVER hand over your passport. Cash deposit only ($100–$200). Photograph + video the bike from every side before riding off. Yellow plate = legal; white plate = illegal and impoundable.","International Driving Permit is required by law and Bali police run tourist checkpoints. No IDP = on-the-spot 1,000,000 IDR (~$65) fine, sometimes more. Bring it from home — you cannot get one in Bali.","Bali Belly hits ~30% of first-timers. Sealed bottled water only (even for brushing teeth in cheap rooms), hot food, peel fruit yourself. Stock Imodium + Hydralyte before you fly.","Use Grab and Gojek apps; the local taxi mafia bans them inside Ubud town centre — walk 5 min to a side lane (off Monkey Forest Road) before booking."]'::jsonb,
  '[{"name":"Ubud","safetyRating":4,"vibe":"Yoga, jungle, retreats, vegan cafés, slow","stayHere":true,"notes":"Best base for first-time solo women. Penestanan and Nyuh Kuning are quieter walkable lanes. Avoid Monkey Forest Road after dark."},{"name":"Canggu","safetyRating":3,"vibe":"Surf, digital nomads, beach clubs, scooters everywhere","stayHere":true,"notes":"Berawa is calmer than Batu Bolong. Watch for scooter snatch-thefts on Echo Beach Road. Co-working stays (Tropical Nomad, Outpost) are great for solo women."},{"name":"Seminyak / Kuta","safetyRating":2,"vibe":"Nightlife, malls, mass tourism","stayHere":false,"notes":"Highest scam + drink-spiking density on the island. Day-trip for shopping and sunset; sleep elsewhere. Avoid Kuta nightclubs solo."},{"name":"Sanur","safetyRating":5,"vibe":"Quiet beach, retiree pace, family-friendly","stayHere":true,"notes":"Safest beach town. Cycle the boardwalk. Fast boats to Nusa Lembongan and Penida leave from here every morning."}]'::jsonb,
  '[{"title":"Money-changer short-count","severity":"critical","where":"Bali — Kuta, Legian, Seminyak high streets","what":"Storefronts advertising ‘0% commission, best rate’ short the count by 50,000–500,000 IDR ($3–35) in the bundle. Operators distract with calculator, snap a few notes back during the count.","avoid":"Only use Central Kuta Money Exchange, BMC, or Dirgahayu — listed on Google Maps with 4.5+ stars and a glass-cage front. Count notes yourself before stepping away. Refuse any place with hand-painted ‘0% commission’ signage."},{"title":"Scooter rental damage + passport hostage","severity":"critical","where":"Bali — every tourist hub, especially Canggu, Kuta, Ubud","what":"Rental shop demands passport as deposit. On return, they claim pre-existing scratches or ‘engine damage’ and refuse to release the passport unless you pay $200–$2,000.","avoid":"Cash deposit only ($100–$200). Photograph and video the entire bike (all sides, mirrors, tyres, engine) before riding off. Use shops your hostel or villa explicitly recommends. Yellow plate only."},{"title":"ATM skimming","severity":"high","where":"Bali — standalone ATMs at Kuta beach road, Ubud Monkey Forest Road, Canggu corners","what":"Skimming device + pinhole camera. Account drained 1–8 hours after the transaction. BNI and BCA standalone kiosks are most-reported.","avoid":"Use ATMs INSIDE bank branches only — BCA, Mandiri, BNI lobbies. Cover PIN entry. Set a low daily withdrawal cap with your home bank before the trip."},{"title":"DPS airport ‘official taxi’ upcharge","severity":"high","where":"Bali — Ngurah Rai (DPS) airport arrivals","what":"‘Official airport taxi’ counters charge 350,000–600,000 IDR for a ride that costs 100,000 IDR on Grab. Some take you to a kickback-paying hotel claiming yours ‘closed’.","avoid":"Walk past the taxi counter, exit the terminal, cross the parking lot to the public road, then book Grab or Gojek there. Or pre-book a private transfer through your hotel before arrival."},{"title":"Drink spiking + arak methanol (Kuta / Legian)","severity":"critical","where":"Bali — Sky Garden, Bounty, La Favela, Kuta beachfront bars","what":"GHB / rohypnol in drinks; victim wakes up missing money, phone, sometimes assaulted. Local arak (moonshine) has been mixed with methanol — multiple tourist deaths through 2024–2025.","avoid":"Avoid Kuta nightclubs solo. Sealed branded beer or sealed bottles only. Watch the bartender pour. Never accept drinks from strangers. ‘Free arak shot’ = walk out."},{"title":"Ubud taxi mafia overcharge","severity":"medium","where":"Bali — Ubud Monkey Forest Road, Hanoman Street","what":"Painted ‘Taxi?’ signs on every corner. Locals refuse the meter, quote 200,000 IDR for a 30,000 IDR ride. Local mafia blocks Grab / Gojek pickups inside Ubud town centre.","avoid":"Walk 5–10 min to a side lane off Monkey Forest Road and book Grab there. Or take a Bluebird (Bali Taxi) blue cab — they run the meter without arguing."},{"title":"Monkey theft at Sacred Monkey Forest","severity":"medium","where":"Bali — Ubud Sacred Monkey Forest, Uluwatu Temple","what":"Macaques snatch sunglasses, phones, water bottles, hats. Some are trained by handlers who then ‘help’ retrieve the item for a 50,000–200,000 IDR ‘tip’.","avoid":"No sunglasses, no loose accessories. Phone in a zipped pocket, not in hand. If snatched, do NOT chase — flag down a uniformed ranger; staff retrieve items for free."},{"title":"‘Free’ temple sarong / friendship bracelet","severity":"medium","where":"Bali — temple entrances at Tanah Lot, Uluwatu, Ubud Saraswati","what":"Hawker ties a sarong or bracelet on you ‘free as a gift’ then aggressively demands 50,000–200,000 IDR. Refusal escalates to a scene.","avoid":"Refuse all unsolicited offers. Most temples already include sarong rental in the entry ticket. Walk past with hands together, polite ‘no thank you.’"},{"title":"Black-market visa-extension scam","severity":"high","where":"Bali — ‘visa agents’ on Jalan Legian, Instagram DMs targeting nomads","what":"‘Agent’ takes $200 + your passport for a B211 extension or KITAS application; either disappears or files a fake stamp that gets you fined or banned at exit.","avoid":"Use only verified agents (Bali Visa Service, Emerhub, Cekindo) with a physical office, registered tax number, and Google reviews. Or extend yourself through the official imigrasi.go.id e-Visa portal."},{"title":"Beach-towel / massage upsell on Kuta sand","severity":"medium","where":"Bali — Kuta Beach, Legian Beach, Seminyak Beach","what":"Beach hawker offers ‘free’ massage or ‘free’ towel use, then charges 200,000–500,000 IDR after, blocking access to your bag while ‘helping’ you up.","avoid":"Polite firm decline. Book massage at a registered spa with posted prices (Karma, Bodyworks, Putri Bali Spa). Never leave your bag with a hawker."}]'::jsonb,
  '[{"mode":"Grab + Gojek apps","tip":"Both run cars and motorbike-taxis. Cheaper than the airport meter. Banned by the local mafia in Ubud town centre — walk 5 min outside before booking. Save the Bahasa name of your destination in the app to skip language friction.","approxCost":"30,000–80,000 IDR ($2–5) most rides; 100,000–150,000 IDR ($6–10) airport → Seminyak"},{"mode":"Bluebird (Bali Taxi) blue metered cabs","tip":"The only taxi brand that runs the meter without arguing. Look for the literal blue colour + Bluebird logo on the door (other ‘blue’ cabs are imitators). Available at airport, malls, hotel ranks.","approxCost":"Meter starts at 7,000 IDR + 7,000 IDR/km"},{"mode":"Scooter self-drive","tip":"Easiest way around. International Driving Permit REQUIRED — police run tourist checkpoints. Yellow plate only. Always wear a helmet. Confirm your travel insurance covers scooters in Indonesia (most don’t by default).","approxCost":"70,000–120,000 IDR/day ($4–8); helmet usually included"},{"mode":"Perama Tours shuttle bus","tip":"Reliable shared van between Ubud, Kuta, Sanur, Padang Bai (Lombok ferry), Lovina. Book at any Perama office or guesthouse. Slow but the safest non-driving option for solo women.","approxCost":"60,000–125,000 IDR per leg"}]'::jsonb,
  '[{"name":"Tirta Empul Holy Spring (early morning)","type":"Active Hindu temple + ritual bathing","angle":"Solo-female specific","why":"Active Balinese Hindu purification temple. Arrive 7am before tour buses; you’ll have the spring almost to yourself. Sarong included; women on period are asked not to enter the spring (sit by the side, observe).","approxCost":"75,000 IDR entry + 10,000 IDR locker"},{"name":"Sidemen Valley homestays","type":"Quiet rural alternative to Ubud","angle":"Combined (FO + FM)","why":"1.5 hrs east of Ubud. Rice terraces, no scooter horns, family-run homestays under $25/night. The escape-Ubud move. Try Subak Tabola Villa or Samanvaya.","approxCost":"$15–$50/night"},{"name":"Munduk waterfalls + lake-rim cafés","type":"Cool-climate hill town","angle":"FO+FM","why":"Mountain village 2.5 hrs north of Ubud. Cool air, three waterfalls walkable from town, sunrise at Lake Tamblingan. Low-tourist, female-run guesthouses.","approxCost":"$25–$70/night"},{"name":"Nusa Lembongan via Sanur fast boat","type":"Day trip / 2-night escape","angle":"FO+FM","why":"30-min boat from Sanur. Way quieter than Penida. Snorkel with manta rays at Manta Point, cycle the island, sunset at Devil’s Tear. Solo-female-friendly homestays at Mushroom Bay.","approxCost":"Boat round-trip 250,000 IDR; rooms from $20"},{"name":"Pranoto’s Art Gallery drop-in life-drawing class (Ubud)","type":"Drop-in life-drawing class","angle":"Solo-female","why":"Run by Pranoto and his wife Kerry; $10 drop-in life-drawing class twice a week. Easiest place in Ubud to meet other solo travellers without a yoga-studio price tag.","approxCost":"≈ $10 / 150,000 IDR per class"}]'::jsonb,
  '["Photocopy + photograph passport, credit cards, insurance — store on cloud + a backup phone","Get an International Driving Permit BEFORE you fly if you plan to scooter (Indonesian police will fine you 1M+ IDR without it)","Buy World Nomads or SafetyWing insurance covering scooter accidents in Indonesia (most insurers exclude scooters by default)","Pre-book first 2 nights of stay; don’t arrive in Bali without a confirmed bed","Download Grab + Gojek apps and verify they work on your home SIM before flying"]'::jsonb,
  '{"do":["Stay in Sanur or Ubud for your first 2 nights — easier landing than Kuta or Canggu","Carry small cash (10,000 / 20,000 / 50,000 IDR notes) — many places refuse 100k notes for small purchases","Wear a sarong covering knees and shoulders at every temple, including Uluwatu and Tanah Lot","Drink only sealed bottled water, even for brushing teeth in cheap rooms"],"dont":["Hand over your passport for any rental (scooter, surfboard, motorbike) — cash deposit only","Drink the local arak / moonshine — multiple methanol-poisoning deaths through 2024–2025","Eat ice or unpeeled salads in cheap warungs — Bali Belly hits 30%+ of first-time visitors","Trust ‘visa agents’ on Jalan Legian or Instagram DMs — extend at imigrasi.go.id directly"]}'::jsonb,
  '{"currency":"USD","backpacker":30,"midRange":80,"comfortable":200}'::jsonb,
  '[{"label":"Police","number":"110"},{"label":"Ambulance","number":"118"},{"label":"Tourist Police (Bali)","number":"0361-754599"},{"label":"Bali Tourism Helpline","number":"0361-222387"}]'::jsonb,
  FALSE,
  NULL,
  '{"booking":"https://www.booking.com/searchresults.html?ss=Bali&aid=PLACEHOLDER","worldNomads":"https://www.worldnomads.com/travel-insurance?affiliate=PLACEHOLDER"}'::jsonb
),
(
  'chiang-mai-thailand',
  'Chiang Mai',
  'Thailand',
  'both',
  'ananya-mumbai',
  '2026-04-28'::date,
  6,
  '/images/intel/chiang-mai-thailand.jpg',
  '["Burning season Feb–April: AQI regularly hits 200+, schools close, the haze is brutal. Plan visits May–Oct, or bring P95/N95 masks if you must come Feb–April.","Songthaews (red shared trucks) are flat-rate inside the Old City — 30 THB per person. Anything more is overcharging; say ‘30 baht?’ before getting in and walk if they refuse.","Use Grab for cars and Bolt for motorbike-taxis. Tuk-tuks will quote 200 THB for a 60 THB ride. Songthaew + Grab is the no-haggle combo.","The Old City (inside the moat) is the safest first base — every temple is walkable, hostels are everywhere, well-lit at night.","Sunday Walking Street (Ratchadamnoen Rd) is one of the safest large markets in SE Asia for solo women — go after 5pm, easy to navigate alone."]'::jsonb,
  '[{"name":"Old City (inside the moat)","safetyRating":5,"vibe":"Temples, hostels, walkable, gentle traveller energy","stayHere":true,"notes":"Best first base. Tha Pae Gate side is liveliest; Suan Dok Gate side quieter. Stick to inside the moat after 9pm and you’re fine."},{"name":"Nimman / Suthep","safetyRating":4,"vibe":"Cafés, digital nomads, co-working, modern","stayHere":true,"notes":"Soi 1–7 has the best café cluster. Maya Mall is a navigation landmark. A 10-min songthaew ride to the Old City."},{"name":"Santitham / Chang Phueak","safetyRating":4,"vibe":"Local life, cheap street food, residential","stayHere":true,"notes":"Where Thais actually live. North gate (Chang Phueak) night market for fewer tourists, real prices. Good if you’re on a budget."},{"name":"Riverside (Ping River) / Loi Kroh","safetyRating":3,"vibe":"Upscale hotels + nightlife strip","stayHere":false,"notes":"Loi Kroh Road has go-go bars and the most-reported drink-spiking density in Chiang Mai. Stay across the river or in the Old City instead."}]'::jsonb,
  '[{"title":"Tuk-tuk gem-shop / tailor scam","severity":"high","where":"Chiang Mai — around Tha Pae Gate, Wat Phra Singh, Night Bazaar","what":"Tuk-tuk driver offers ‘cheap city tour, 100 THB’; route detours to a ‘government tax-free gem store’ or tailor where you’re pressured to buy. Smaller and less aggressive than Bangkok’s version, but the same play.","avoid":"Skip any ‘100 THB tour’ offered on the street. Walk to temples or use Grab. If you want a tuk-tuk ride, fix the price and the destination — no detours."},{"title":"Songthaew tourist overcharge","severity":"medium","where":"Chiang Mai — pickups outside Tha Pae Gate, Night Bazaar, Maya Mall","what":"Driver quotes 100–200 THB for the standard 30 THB Old-City ride, especially with bags or after dark. Refuses to share with other passengers (the whole point of songthaew).","avoid":"State ‘30 baht?’ before getting in. If it’s further (Nimman → Old City: 40–50 THB; longer: agree first). Walk to the next songthaew if they hold out — the next one says yes."},{"title":"Scooter rental damage + passport hostage","severity":"critical","where":"Chiang Mai — Old City rentals, Doi Suthep approach road, Pai-bound shops","what":"Shop demands passport as deposit. On return, claims pre-existing scratches or ‘engine damage’; refuses to release passport unless you pay 5,000–30,000 THB.","avoid":"Cash deposit only (1,000–3,000 THB). Photograph and video the bike from every side BEFORE riding off. Use Mr Mechanic, Tony’s Big Bikes, Cat Motors — well-reviewed, written contracts, no passport."},{"title":"Fake monk bracelet shake-down","severity":"medium","where":"Chiang Mai — outside Wat Phra Singh, Wat Chedi Luang, Tha Pae Gate","what":"Costumed ‘monk’ ties an orange thread / bracelet on you ‘for blessings’ then demands 100–500 THB. Real Thai monks do not solicit on the street and do not touch women.","avoid":"Real monks: shaven head, plain saffron robes, no jewellery, walk silently early-morning alms route. If approached: hands together (‘wai’), polite ‘mai pen rai’, walk past."},{"title":"Unethical ‘elephant sanctuary’","severity":"high","where":"Chiang Mai — Mae Taeng valley, Mae Wang, day-tour bookings","what":"Operators advertising ‘elephant sanctuary’ or ‘ethical interaction’ that secretly include riding, washing chained elephants, or chained training (phajaan). Bull-hooks on site = unethical.","avoid":"Only Elephant Nature Park (Lek Chailert) and BLES (Boon Lott’s Elephant Sanctuary) are independently verified — observation-only, no riding, no washing. Avoid any operator listing ‘elephant ride / bath’ in the same package."},{"title":"Trekking operator without insurance","severity":"high","where":"Chiang Mai — Mae Hong Son loop, Doi Inthanon, Pai jungle treks","what":"Cheap trekking operators (under 800 THB / day) cut corners on guides, helmets, first aid; multiple deaths from cliff falls and motorbike crashes through 2024–2025 reported by the Chiang Mai Mail.","avoid":"Use Pooh Eco-Trekking, Chai Lai Sisters, or Trekking Collective — TAT-licensed, insured, posted safety briefings. Confirm insurance coverage and emergency contact in writing before paying."},{"title":"ATM skimming","severity":"high","where":"Chiang Mai — standalone ATMs at Tha Pae Gate, Night Bazaar, Nimman corners","what":"Skimmer + pinhole camera; account drained 1–8 hours after withdrawal. Bangkok Bank and Krungsri standalone kiosks are most-reported.","avoid":"Use ATMs INSIDE bank branches only — Siam Commercial Bank, Bangkok Bank, Kasikorn lobbies. Cover PIN entry. Set a low daily withdrawal cap with your home bank."},{"title":"‘Real silver’ / ‘antique’ counterfeit at Sunday Walking Street","severity":"medium","where":"Chiang Mai — Sunday Walking Street, Saturday Walking Street, Night Bazaar","what":"Mass-produced trinkets sold as ‘authentic Lanna antique’ for 2,000–8,000 THB. Often German silver (zinc alloy) sold as 925 sterling.","avoid":"Treat the markets as fun craft shopping, not investment. Real Lanna antiques only at certified dealers (Suriwong Book Centre area). 925 stamp + magnet test (real silver = non-magnetic)."},{"title":"Cooking class double-booking / no-show","severity":"medium","where":"Chiang Mai — Old City booking touts, Instagram DMs","what":"Tout in the Old City sells you a ‘half-day cooking class, 800 THB’; the operator never picks you up, or the same class is double-booked and the second group is left at the rendezvous.","avoid":"Book directly with operators: Thai Farm Cooking School, Asia Scenic, Mama Noi’s — TripAdvisor 4.5+ stars. Pay deposit only via the operator’s own website, not via a tout."},{"title":"Drug-bust setup at nightlife strips","severity":"critical","where":"Chiang Mai — Loi Kroh Road, Zoe in Yellow / Tha Pae Gate cluster","what":"‘Friendly’ stranger offers a small bag of weed or pills; minutes later a plainclothes ‘cop’ appears, demands 30,000–80,000 THB to avoid arrest. Thai narcotics laws are harsh — even small amounts can mean weeks in detention.","avoid":"Refuse every offer regardless of how casual. If approached by an alleged officer, ask for ID and station name; insist on going to the actual police station — the scammer will vanish."}]'::jsonb,
  '[{"mode":"Grab + Bolt apps","tip":"Grab for cars, Bolt for motorbike-taxis (about 30% cheaper than Grab here). Both more transparent than tuk-tuks. Save your hostel’s Thai-script address in the app for driver clarity.","approxCost":"60–150 THB ($2–4) most rides; 200–280 THB airport → Old City"},{"mode":"Songthaew (red shared trucks)","tip":"Flat 30 THB anywhere inside / next-to the Old City. Hail one heading roughly your direction, tell driver the destination, hop in the back. The single best-value transport in northern Thailand.","approxCost":"30 THB / person flat-rate; 40–50 THB to outer neighbourhoods"},{"mode":"Scooter self-drive","tip":"Easiest for Doi Suthep, Mae Sa, San Kamphaeng. International Driving Permit REQUIRED (police checkpoints near Doi Suthep). Always wear a helmet — non-negotiable, 2,000 THB fine. Do NOT ride into Pai unless you’re an experienced rider; the road kills people every year.","approxCost":"200–350 THB / day; helmet included"},{"mode":"Long-distance bus / minivan to Pai, Chiang Rai, Mae Hong Son","tip":"Aya Service and Prempracha run Pai (3 hr), Sombat Tour to Chiang Rai (3 hr), Prempracha to Mae Hong Son. Buy tickets at the operator’s real office (Arcade Bus Station) — never from a Walking Street tout.","approxCost":"150–300 THB Pai; 200–350 THB Chiang Rai"}]'::jsonb,
  '[{"name":"Wat Pha Lat (the hidden monastery)","type":"Forest temple, halfway up Doi Suthep","angle":"Solo-female specific","why":"Skipped by every tour bus. Walk the Monk’s Trail (1.5 km, 30 min) up from the foot of Doi Suthep through the forest — you’ll arrive at a moss-covered, near-empty temple before the main one. Best done 7–9am.","approxCost":"Free; songthaew to trailhead 50 THB"},{"name":"Mae Sa Valley women’s craft villages","type":"Day trip — weaving + textile cooperatives","angle":"Combined (FO + FM)","why":"Female-run weaving co-ops in Ban Pa Pong (Mae Rim) and Bo Sang. Buy directly from the makers, see the looms, no tour-guide markup. Pair with the orchid farm or Mon Cham viewpoint.","approxCost":"Songthaew round-trip 400 THB or scooter; scarves 200–800 THB direct"},{"name":"Mon Cham / Pong Yang viewpoint","type":"Hill-station sunset","angle":"FO+FM","why":"1 hr north of Chiang Mai. Open-air restaurants on a ridge with terraced strawberry farms below; sunset is theatrical. Way quieter than Doi Suthep at sunset, no tour buses, ample solo seating.","approxCost":"Scooter / Grab ~600 THB; meals 150–400 THB"},{"name":"The Sustainable Studio (Sunday market alternative)","type":"Woman-run zero-waste design space","angle":"Solo-female","why":"Founded by Phichit and her partner. Workshops (natural dye, batik, plant-based papermaking), curated local-maker shop, café. The opposite vibe to the Walking Street tourist crush.","approxCost":"Free entry; workshops 1,200–2,500 THB"},{"name":"Pai (3-day side trip)","type":"Mountain town, hot springs, slow days","angle":"FO+FM","why":"3 hours and 762 curves north of Chiang Mai by minivan. Solo-female-friendly hostels (Spicy Pai Backpackers, Pai Country Hut), waterfalls, hot springs, the Pai Canyon at sunset. Travel in a group on the minivan; the road is brutal.","approxCost":"Minivan 150–200 THB each way; hostels 200–600 THB / night"}]'::jsonb,
  '["International Driving Permit if you plan to scooter (Thai police run checkpoints; no IDP = 1,000 THB fine + bike impound)","Travel insurance covering scooters and treks in Thailand (most policies exclude scooters by default — World Nomads or SafetyWing add it)","Verify cooking class / trekking operator on TripAdvisor (4.5+ stars, 100+ reviews) before paying any deposit","Burning-season check (aqicn.org / Chiang Mai) — if AQI > 150 forecast for 3+ days, consider rescheduling Feb–April","Pre-book first 2 nights inside the Old City; don’t arrive in Chiang Mai without a confirmed bed"]'::jsonb,
  '{"do":["Walk inside the Old City after dark — it’s safer than most home cities","Do the Monk’s Trail to Wat Pha Lat at sunrise — alone, on foot, before the songthaews fire up","Use the moat road as your bearings — it’s a perfect 1.5 × 1.5 km square","Tip cooking-class teachers + multi-hour guides 100–200 THB; not standard but appreciated"],"dont":["Touch a monk or hand anything directly to one — women, observe and pass via cloth or via a male intermediary","Wear shorts above the knee or sleeveless tops to temples — Doi Suthep enforces strictly, sarongs available at the gate","Photograph monks, especially women novices, without explicit permission","Ride elephants or book any ‘sanctuary’ that includes riding or chain-washing — every reputable list dropped these by 2023"]}'::jsonb,
  '{"currency":"USD","backpacker":25,"midRange":60,"comfortable":140}'::jsonb,
  '[{"label":"Police","number":"191"},{"label":"Tourist Police","number":"1155"},{"label":"Ambulance","number":"1669"},{"label":"Fire","number":"199"},{"label":"Chiang Mai Tourism","number":"053-248604"},{"label":"Women''s Helpline (MoSDHS)","number":"1300"}]'::jsonb,
  FALSE,
  NULL,
  '{"booking":"https://www.booking.com/searchresults.html?ss=Chiang+Mai&aid=PLACEHOLDER","worldNomads":"https://www.worldnomads.com/travel-insurance?affiliate=PLACEHOLDER"}'::jsonb
),
(
  'lisbon-portugal',
  'Lisbon',
  'Portugal',
  'both',
  'ananya-mumbai',
  '2026-04-28'::date,
  6,
  '/images/intel/lisbon-portugal.jpg',
  '["Tram 28 is one of Europe’s most-pickpocketed routes — Lisbon police estimate 70% of pickpocket victims are women. Crossbody bag in front, phone in a zipped pocket, hands on the bag at every stop.","Use Bolt, FreeNow, or Uber from the airport — they’re ~€8 cheaper than the ‘official’ taxi rank (which charges €18–25 for the €10–14 ride into the city).","The ‘couvert’ on your table (bread, olives, cheese, sardine paste) is NEVER free — €3–15 per plate. Push it back to the waiter if you don’t want it; you only pay for what you eat.","Drug pushers in Bairro Alto, Chiado, and Praça do Comércio offer ‘cocaine / hash’ on the street — almost always oregano sold at €40 a gram. Refuse all; in some cases plainclothes officers run entrapment stings.","Lisbon’s calçada (mosaic cobblestone) is gorgeous and lethal in the rain. Grippy soles (not your nice flats), and plan flat days (Baixa, Belém by tram) vs hill days (Alfama, Graça)."]'::jsonb,
  '[{"name":"Príncipe Real / Avenida","safetyRating":5,"vibe":"Leafy, upscale, design shops, quiet residential","stayHere":true,"notes":"Safest base for first-time solo women. Walk to Bairro Alto for nightlife, Chiado for shopping, Liberdade Metro 5 min away. Embaixada concept-store + Sunday biological market (Príncipe Real Garden)."},{"name":"Alfama","safetyRating":4,"vibe":"Oldest quarter, fado bars, narrow lanes, photogenic","stayHere":true,"notes":"Atmospheric and walkable. Watch your bag in Largo do Chafariz de Dentro and along the tram-28 route. Avoid the steep south-side lanes alone after midnight."},{"name":"Baixa / Chiado","safetyRating":4,"vibe":"Central grid, walkable, shops, restaurants","stayHere":true,"notes":"Great first base if you want to be in the middle of everything. Praça do Comércio gets shell-game scammers; Rua Augusta has the worst restaurant tourist traps. Stay one street off the main axis."},{"name":"Bairro Alto","safetyRating":3,"vibe":"Nightlife, cocktail bars, drug pushers after midnight","stayHere":false,"notes":"Daytime is empty and lovely; from 11pm it’s street-drinking, drug-pusher density and noise. Visit, don’t sleep here. If you stay anyway, pick a building with a lift and door buzzer."}]'::jsonb,
  '[{"title":"Tram 28 organised pickpocket gangs","severity":"critical","where":"Lisbon — Tram 28 (and Tram 12, 24) full route, peak at Sé Cathedral, Miradouro de Santa Luzia, Graça","what":"Coordinated teams (often 3–4 people, sometimes children) crowd you at the door, distract by ‘falling’ or asking the time, and lift wallet / phone in seconds. Lisbon police: women are 70% of victims, phones the most-stolen item.","avoid":"Crossbody bag IN FRONT, hand on it. Phone in a zipped inside pocket — never back pocket, never in hand near a stop. Stand AWAY from the doors at every stop. Pre-book the Sé / Castelo direction in a Bolt instead if you’re carrying valuables."},{"title":"Fake-police ‘wallet check’","severity":"high","where":"Lisbon — Baixa, Rossio, near Praça do Comércio, Belém","what":"Plainclothes ‘officers’ flash a fake badge, claim ‘checking for counterfeit notes’, ask to see your wallet — pocket cash and cards while ‘inspecting’.","avoid":"Real Portuguese police never demand your wallet on the street. Politely say ‘I’ll come to the police station with you’ — the scammer will leave. Call 112 if pressured."},{"title":"Three-card monte / shell game","severity":"medium","where":"Lisbon — Praça do Comércio, Rossio Square, Rua Augusta","what":"Crew of 3–5 working together; first ‘player’ wins big to draw you in; you’re fleeced for €50–500 in three rounds. Always rigged.","avoid":"Walk past. Never engage, never ‘just one round’. If you see one going, the pickpockets are working the crowd around it — keep moving and check your bag."},{"title":"Restaurant couvert / no-price surprise charge","severity":"high","where":"Lisbon — Rua Augusta, near Sé Cathedral, Belém around the Pastéis line","what":"Bread, olives, cheese, sardine paste appear on the table without being ordered — €3–15 each plate, added to the bill. ‘Specials of the day’ verbally pitched without prices = €40+ a plate.","avoid":"Anything you didn’t order, push back to the waiter — you don’t pay for what you didn’t accept. Read menu prices for every item before agreeing. Avoid restaurants with hawkers outside; Time Out Market and side-street tascas are honest-priced."},{"title":"Bird poop / mustard distraction theft","severity":"medium","where":"Lisbon — Praça do Comércio, Belém Tower / Jerónimos line, Miradouros","what":"Substance lands on your shoulder; ‘kind stranger’ offers to clean while accomplice picks pocket. Identical to the Rome / Barcelona pattern.","avoid":"Politely refuse help. Move into a café or shop before cleaning. Never put your bag down."},{"title":"Airport ‘official taxi’ overcharge","severity":"high","where":"Lisbon — Humberto Delgado (LIS) airport taxi rank","what":"Official meter cabs charge €18–25 for a €10–14 ride into the city. Some quote ‘flat €40’ for the same trip and refuse the meter. ‘Luggage fees’ added at €1.60 per bag without warning.","avoid":"Walk to Departures (one floor up) — Bolt / Uber / FreeNow pickups there avoid the rank fee, run €10–14 to anywhere central. Or take the Metro Linha Vermelha (red line) — €1.85 to Saldanha / Alameda."},{"title":"ATM skimming","severity":"high","where":"Lisbon — standalone ATMs in Baixa, Bairro Alto, Belém near tourist sites","what":"Skimmer + pinhole camera. Account drained 1–8 hours after withdrawal. Multibanco machines OUTSIDE bank lobbies are most-reported.","avoid":"Use ATMs INSIDE bank branches only — Caixa Geral, Millennium BCP, Santander, Novo Banco lobbies. Cover PIN entry. Choose ‘charge in EUR’ if asked (DCC ‘home currency’ option = 5–8% worse rate)."},{"title":"‘Cocaine / hashish?’ oregano-pusher","severity":"medium","where":"Lisbon — Bairro Alto, Chiado, Praça do Comércio, Rossio after dark","what":"Street pusher offers ‘cocaine, hashish’ at €40 a gram — overwhelmingly it’s oregano, talc, or paracetamol. Some are paired with plainclothes-officer entrapment stings; either way, you walk away poorer or with a record.","avoid":"Polite firm ‘no thank you’, keep walking. They’re looking for hesitation; if you stop, they pivot to harder pitches. Don’t make eye contact."},{"title":"Online apartment rental fraud","severity":"critical","where":"Lisbon — direct WhatsApp / Facebook Marketplace / Instagram DMs, especially Alfama and Bairro Alto listings","what":"‘Owner’ messages with a too-good price, asks for a wire transfer or Western Union deposit; the apartment doesn’t exist or the keys never arrive. Increasingly common as Lisbon’s rental crisis pushes scammers up-market.","avoid":"Book ONLY through Booking.com, Airbnb’s official app, or VRBO. Pay via the platform, never wire-transfer or PayPal F&F. Verify the building exists on Google Street View before paying."},{"title":"‘Free’ rose / friendship bracelet near tourist sites","severity":"medium","where":"Lisbon — Belém Tower / Jerónimos approach, Sé Cathedral steps, Castelo de São Jorge gates","what":"Hawker presses a rose into your hand or ties a bracelet on your wrist ‘a gift’, then aggressively demands €5–20. Refusal escalates to a scene.","avoid":"Hands in pockets when approached. Polite firm ‘no’, walk past. If tied: take it off, drop it, walk on — don’t pay."}]'::jsonb,
  '[{"mode":"Bolt + Uber + FreeNow apps","tip":"Bolt is usually cheapest in Lisbon. FreeNow is best for booked-ahead. Uber for English-only drivers. Airport pickups are at Departures (one level up), not the official taxi rank.","approxCost":"€5–10 most central rides; €10–14 airport → city centre"},{"mode":"Lisbon Metro (Viva Viagem card)","tip":"Buy a Viva Viagem card from any Metro vending machine (€0.50 once) and load €1.85 per ride OR a 24-hr pass (€6.80). Verde (green) and Azul (blue) lines cover most tourist needs. Verify your destination has step-free access if mobility-limited.","approxCost":"€1.85 per ride; €6.80 / 24-hr unlimited"},{"mode":"Tram 28 (with pickpocket caution)","tip":"Iconic but the most-targeted pickpocket route in the city. If you ride: stand AWAY from doors at every stop, crossbody bag in front, no phone in hand. Better still — ride at 7:30am before the crowds, you’ll have a seat and clean photos.","approxCost":"€3 single ride (cash) or €1.85 with Viva Viagem"},{"mode":"Aerobus / Metro Linha Vermelha (airport)","tip":"Linha Vermelha (red Metro line) connects LIS airport to Saldanha and Alameda in 20 min for €1.85. Aerobus runs 7am–11pm, €4 to most central drops. Both are cheaper and more honest than the airport taxi rank.","approxCost":"€1.85 Metro / €4 Aerobus"}]'::jsonb,
  '[{"name":"LX Factory Sunday market + women-led studios","type":"Repurposed industrial complex with maker shops + Sunday market","angle":"Combined (FO + FM)","why":"Old print factory turned co-working / shop / studio cluster under the 25 de Abril Bridge. Sunday market 11am–7pm has women-led ceramics, leather, illustration, vintage. Way calmer than Time Out Market for solo browsing.","approxCost":"Free entry; coffee €2.50, lunch €10–18"},{"name":"Costa da Caparica (beach by ferry)","type":"Day-trip Atlantic beach","angle":"Solo-female specific","why":"30 min from Lisbon (ferry to Cacilhas + bus 124, or Metro Sul do Tejo). 30 km of dunes; stop 8 (Praia da Saúde) and stop 14 (Praia do Castelo) are the safest, most family-friendly stretches. Lifeguards in summer.","approxCost":"Ferry + bus combo €5 round-trip"},{"name":"Sintra at sunrise (Pena Palace, 8am opening)","type":"UNESCO palace day trip","angle":"FO+FM","why":"By 11am Sintra is a tour-bus zoo. Take the 6:42am train from Rossio (€2.30), be at Pena Palace gates for the 8:00 opening, you’ll have the terraces almost alone for an hour. Pre-book timed entry online — 6 weeks ahead in summer.","approxCost":"Train €4.60 round-trip; Pena entry €14"},{"name":"Time Out Market counter seating (solo-friendly)","type":"Curated food hall, solo-comfortable","angle":"Solo-female","why":"Yes, it’s touristy. But the counter seats at Henrique Sá Pessoa, Manteigaria, and Marlene Vieira are designed for solo eaters and the staff are used to women dining alone. Best low-stress first dinner in Lisbon.","approxCost":"Mains €10–22; pastel de nata €1.30"},{"name":"Miradouro de Santa Catarina (sunset)","type":"Free local viewpoint, no entry fee","angle":"FO+FM","why":"Locals call it ‘Miradouro do Adamastor’. Free, no fence, no ticket queue. River + bridge sunset view, kiosk café for €4 sangria, eclectic crowd of Lisbon students. Skip Miradouro de São Pedro de Alcântara unless you want the tour bus."}]'::jsonb,
  '["Buy a Viva Viagem card on arrival at the Metro vending machine (€0.50 once, then load each ride)","Pre-book Sintra Pena Palace timed entry — 6 weeks ahead in summer; 2 weeks off-season","Travel insurance covering pickpocketing + medical (Lisbon hospitals charge non-EU visitors directly)","Confirm any apartment booking ONLY via Booking.com / Airbnb / VRBO official apps — never wire-transfer to a WhatsApp ‘owner’","Pack grippy-soled shoes — Lisbon’s calçada cobblestones are slippery in rain"]'::jsonb,
  '{"do":["Eat pastéis de nata at Manteigaria (Chiado or Time Out) — fresher than the Belém line and a tenth of the wait","Use the Metro for distance, walk for atmosphere — Verde (green) line connects most you’ll need","Carry €5 / €10 notes — many cafés and tascas can’t break a €50","Keep your passport in the hotel safe; carry a photocopy + photo on your phone"],"dont":["Accept the couvert (bread / olives / cheese on the table) without checking the price","Buy ‘cocaine’ in Bairro Alto — it’s oregano at best, an entrapment sting at worst","Photograph people in Alfama windows or doorways without permission — locals push back","Ride Tram 28 with valuables in a back pocket or open bag — pickpockets work this route every day"]}'::jsonb,
  '{"currency":"EUR","backpacker":70,"midRange":150,"comfortable":300}'::jsonb,
  '[{"label":"EU Emergency","number":"112"},{"label":"Police (PSP Tourism)","number":"+351-213-421-634"},{"label":"Ambulance (INEM)","number":"112"},{"label":"Fire","number":"117"},{"label":"APAV Women''s Helpline","number":"116-006"}]'::jsonb,
  FALSE,
  NULL,
  '{"booking":"https://www.booking.com/searchresults.html?ss=Lisbon&aid=PLACEHOLDER","worldNomads":"https://www.worldnomads.com/travel-insurance?affiliate=PLACEHOLDER"}'::jsonb
